/**
 * Sentinel Intelligence Module (Sovereign 2.0)
 * Evaluates documentation substance and quality.
 */

const BOILERPLATE_PHRASES = [
  "implementation details pending",
  "starter template generated by sentinel",
  "requires human and legal review",
  "does not imply final legal compliance",
  "add details here",
  "details about bias assessment",
  "implementation details pending",
  "lorem ipsum",
  "placeholder text"
];

const MIN_SECTION_WORDS = 20;

/**
 * Checks if content contains excessive boilerplate.
 */
function hasBoilerplate(content) {
  const lower = content.toLowerCase();
  return BOILERPLATE_PHRASES.some(phrase => lower.includes(phrase)) || 
         lower.includes('lorem ipsum') || 
         lower.length < 50;
}

/**
 * Analyzes the substance of a documentation file content.
 * @param {string} content - Markdown content of a documentation file.
 * @returns {object} { score: number (0-1), findings: string[] }
 */
function analyzeSubstance(content) {
  if (!content || content.trim().length === 0) {
    return { score: 0, findings: ["File is empty."] };
  }

  const findings = [];
  const lowerContent = content.toLowerCase();
  let boilerplateMatches = 0;

  // 1. Check for boilerplate phrases
  BOILERPLATE_PHRASES.forEach(phrase => {
    if (lowerContent.includes(phrase)) {
      boilerplateMatches++;
      findings.push(`Boilerplate detected: "${phrase}"`);
    }
  });

  // 2. Word Count Heuristics
  const wordCount = content.split(/\s+/).length;
  if (wordCount < 40) {
    findings.push("Insufficient detail for a legal risk assessment.");
  }

  // 3. Score calculation
  let score = 1.0;
  if (boilerplateMatches > 0) score -= 0.6; // Increased penalty
  if (wordCount < 40) score -= 0.3;
  if (wordCount < 15) score = 0;

  return {
    score: Math.max(0, score),
    findings: findings
  };
}

const ARTICLE_KEYWORDS = {
  'Art. 9': ['risk', 'assessment', 'mitigation', 'impact', 'probability', 'bias', 'protection'],
  'Art. 13': ['transparency', 'disclosure', 'model', 'limitation', 'purpose', 'instructions', 'performance'],
  'Art. 14': ['human', 'oversight', 'intervention', 'override', 'control', 'monitor', 'reviewer'],
  'Art. 20': ['log', 'traceability', 'event', 'record', 'incident', 'storage', 'capabilities']
};

/**
 * Verifies consistency with stricter rules.
 */
function checkConsistency(article, content) {
  if (!content) return { score: 0, matches: [], missing: [] };
  
  // Rule 1: Boilerplate content is automatically marked as low consistency
  if (hasBoilerplate(content)) {
    return { score: 0.1, matches: [], missing: ARTICLE_KEYWORDS[article] || [], note: 'Boilerplate detected' };
  }

  const lowerContent = content.toLowerCase();
  const keywords = ARTICLE_KEYWORDS[article] || [];
  
  const matches = keywords.filter(k => lowerContent.includes(k));
  const missing = keywords.filter(k => !lowerContent.includes(k));
  
  // Rule 2: Require at least 3 distinct keywords to prove "Substantive Context"
  // If only 1-2 keywords found, treat as "Keyword Padding" and penalize
  let score = keywords.length > 0 ? matches.length / keywords.length : 1.0;
  
  if (matches.length < 3 && keywords.length >= 3) {
    score *= 0.4; // Heavy penalty for low keyword density
  }
  
  return {
    score: Math.max(0, score),
    matches,
    missing
  };
}

module.exports = { analyzeSubstance, checkConsistency };
